(', itemModel2, ')')) AS itemModel, IF(itemName = IFNULL(itemName2, itemName), itemName, CONCAT(t.itemName, '
(', itemName2, ')')) AS itemName, t.qty, t.barCodes, t.warrantyEndTime FROM (SELECT contractNo, IF(t.itemCode2 IS NULL, t.itemCode, CONCAT(t.itemCode, '
(', itemCode2, ')')) AS itemCode, CASE WHEN fi.`itemname` IS NULL OR fi.itemname = '' OR fi.itemname = '/' THEN fi.describe_ ELSE fi.itemname END AS itemModel, CASE WHEN fi2.`itemname` IS NULL OR fi2.itemname = '' OR fi2.itemname = '/' THEN fi2.describe_ ELSE fi2.itemname END AS itemModel2, fi.describe_ AS itemName, fi2.describe_ AS itemName2, COUNT(1) AS qty, GROUP_CONCAT(DISTINCT IF(t.barCode2 IS NULL, t.barcode, CONCAT(t.barcode, '(', t.barCode2, ')')) ORDER BY t.barCode SEPARATOR '、' ) AS barCodes, MIN(vw.warrantyEndTime) AS warrantyEndTime FROM ( SELECT DISTINCT vsip.contract_code contractNo, vsip.barcode barCode, vsip.itemCode itemCode, -1 AS transferFlag, vsip.barcode2 barCode2, vsip.itemcode2 FROM view_shipment_info_4_pm vsip LEFT JOIN view_shipment_ems_4_pm vsep ON vsep.contract_code = vsip.contract_code AND vsep.packId = vsip.packId WHERE vsip.contract_code in ($contractNo$) AND NOT EXISTS(SELECT 1 FROM pm_project_shipment pps1 WHERE vsip.barcode = pps1.barcode and contractNo in ($contractNo$) and projectId = #{projectId} ) <if test=" prepend="and" profitCenter> vsip.profitCenter = #{profitCenter} UNION ALL SELECT DISTINCT pps.`contractNo`, pps.`barcode`, pps.`itemCode`, pps.transferFlag, sbr.sn2 as barCode2, sbr.item2 FROM pm_project_shipment pps LEFT JOIN `fb_shipment_barcode_relation` sbr ON sbr.contract = REPLACE(pps.contractNo, '-C', '') AND pps.barcode = sbr.sn1 WHERE contractNo in ($contractNo$) AND projectId = #{projectId} AND EXISTS (SELECT 1 FROM view_shipment_info_4_pm vsip LEFT JOIN view_shipment_ems_4_pm vsep ON vsep.contract_code = vsip.contract_code AND vsep.packId = vsip.packId WHERE vsip.contract_code in ($sourceContractNo$)
AND vsip.barcode = pps.barcode)
) t LEFT JOIN `fb_items` fi ON fi.`item` = t.itemCode LEFT JOIN `fb_items` fi2 ON fi2.`item` = t.itemCode2 LEFT JOIN `view_warranty` vw ON vw.contract_code in ($sourceContractNo$) AND vw.barcode = t.barcode WHERE t.transferFlag != 1 AND vw.warrantyEndTime IS NOT NULL GROUP BY t.itemCode, vw.warrantyEndTime) t ORDER BY t.contractNo, t.itemCode, warrantyEndTime, t.qty DESC;

SELECT DISTINCT fd.`departmentName` AS officeName, t.*, IF( LOCATE( sales.`memberCode`, sales.`memberName` ) > 0, IFNULL(sales.`memberName`, ""), CONCAT( IFNULL( CONCAT(sales.`memberCode`, "-"), "" ), IFNULL(sales.`memberName`, "") ) ) AS salesName, CONCAT( IFNULL(pm1.`memberName`, ""), IFNULL(CONCAT("，", pm2.`memberName`), "") ) AS programName, DATEDIFF(CURDATE(), t.packdate) AS packDays, DATEDIFF( IFNULL(arrivalFinishDate, CURDATE()), t.arrival ) AS arrivalDays, DATEDIFF( IFNULL(preInspectFinishDate, CURDATE()), t.preInspect ) AS preInspectDays, DATEDIFF( IFNULL(finalInspectFinishDate, CURDATE()), t.finalInspect ) AS finalInspectDays FROM (SELECT t.*, DATE(IFNULL( MAX(IF(pppfs.referenceEventName = '到货验收', pppfs.eventPlanHappenDate, NULL)), DATE_ADD(t.packdate, INTERVAL 25 DAY) )) AS arrival, DATE(MAX(IF(pppfs.referenceEventName = '初验', pppfs.eventPlanHappenDate, NULL))) AS preInspect, DATE(MAX(IF(pppfs.referenceEventName = '终验', pppfs.eventPlanHappenDate, NULL))) AS finalInspect FROM (SELECT ph.`projectId`, ph.column001 AS officeCode, pc.`contractNo`, ph.`projectName`, ps.`projectPlanState` AS planState, planState.`basicDataName` AS planStateName, IF(IFNULL(ps.`executionState`, "") = "", ps.projectPlanState, executionState) AS executionState, IF(IFNULL(ps.`executionState`, "") = "", planState.`basicDataName`, execState.`basicDataName`) AS executionStateName, MAX(fs.`packdate`) packdate, MAX( IF ( pt.taskTypeId = 30, pt.eventActualFinishDate, NULL ) ) AS arrivalFinishDate, MAX( IF ( pt.taskTypeId = 60, pt.eventActualFinishDate, NULL ) ) AS preInspectFinishDate, MAX( IF ( pt.taskTypeId = 70, pt.eventActualFinishDate, NULL ) ) AS finalInspectFinishDate FROM pm_project_header ph LEFT JOIN `pm_project_state` ps ON ps.`projectId` = ph.`projectId` LEFT JOIN fnd_basic_data planState ON planState.`dataTypeCode` = '22' AND planState.`effectiveTo` IS NULL AND planState.`basicDataId` = ps.`projectPlanState` LEFT JOIN fnd_basic_data execState ON execState.`dataTypeCode` = 'projectExecutionState' AND execState.`effectiveTo` IS NULL AND execState.`basicDataId` = ps.`executionState` LEFT JOIN pm_project_task pt ON ph.`projectId` = pt.`projectId` AND pt.`effectiveTo` IS NULL LEFT JOIN pm_project_group_relationship pgr ON ph.`projectCode` = pgr.`projectCode` LEFT JOIN pm_project_group pg ON pg.`projectGroupCode` = pgr.`projectGroupCode` LEFT JOIN pm_project_contract pc ON pg.`projectGroupCode` = pc.`projectGroupCode` LEFT JOIN fb_contract fc ON fc.`contract_code` = pc.`contractNo` LEFT JOIN fb_shipment fs ON fc.`contract_id` = fs.`con_id` WHERE ps.`shipmentState` = - 1 AND pt.`effectiveTo` IS NULL AND ph.`effectiveTo` IS NULL AND ( ( FIND_IN_SET(pt.taskTypeId, "30,60,70") AND ph.`projectId` IN (SELECT DISTINCT projectId FROM pm_project_task pt WHERE FIND_IN_SET(pt.taskTypeId, "70") AND pt.eventActualFinishDate IS NULL) ) OR pt.`taskTypeId` IS NULL ) AND ph.`column004` = "运营商市场部" AND ( ph.column011 = 10 OR ph.column011 IS NULL ) AND ph.`projectState` IN (30, 31, 32) GROUP BY ph.`projectId`, pc.`contractNo`) t LEFT JOIN (SELECT DISTINCT pppfs.id, pppfs.contractNo, pppfs.batchCode, pppfs.basicDataName, pppfs.referenceEventName, pppfs.eventPlanHappenDate, pppfs.afterDaysNum, pppfs.eventActualFinishDate, pppfs.marketingFeedback FROM pm_pb_plan_from_sms pppfs LEFT JOIN fnd_basic_data fbd ON fbd.basicDataName = pppfs.referenceEventName WHERE fbd.dataTypeCode IS NOT NULL) pppfs ON pppfs.contractNo = t.contractNo WHERE t.packdate IS NOT NULL GROUP BY t.`projectId`, t.`contractNo`) t LEFT JOIN pm_project_member sales ON sales.`projectId` = t.projectId AND sales.memberRole = '10' AND sales.`effectiveTo` IS NULL LEFT JOIN pm_project_member pm1 ON pm1.`projectId` = t.projectId AND pm1.memberRole = '30' AND pm1.`effectiveTo` IS NULL AND pm1.`fromFlag` = 1 LEFT JOIN pm_project_member pm2 ON pm2.`projectId` = t.projectId AND pm2.`fromFlag` = 2 AND pm2.`effectiveTo` IS NULL AND pm2.memberRole = '30' LEFT JOIN fnd_department fd ON fd.`departmentNum` = t.officeCode
<if test=" prepend="and" officeCode> t.officeCode = #{officeCode}
ORDER BY t.officeCode, t.packdate

