<if test=" salesType> LEFT JOIN (SELECT ph.`projectId`, ph.`projectCode`, ph.`projectName`, IFNULL(IFNULL(MAX(pods.`salesType`), ph.`salesType`), #{defaultSalesType}) salesType FROM `pm_project_header` ph LEFT JOIN `pm_project_group_relationship` pgr ON ph.`projectCode` = pgr.`projectCode` LEFT JOIN `pm_project_contract` pc ON pgr.`projectGroupCode` = pc.`projectGroupCode` LEFT JOIN `pm_order_data_from_sap` pods ON pc.`contractNo` = pods.`contractNo` AND pods.`orderType` = 0 WHERE ph.`projectId` = #{projectId} GROUP BY ph.`projectId`) t ON ph.`projectId` = t.projectId SET ph.`salesType` = IFNULL(t.salesType, #{defaultSalesType})
WHERE ph.`projectId` = #{projectId}

